/* ===============================
   Cosmetic Dentistry Clinic Theme
   Early-2000s corporate/medical style
   =============================== */

:root {
    /* Color system */
    --color-primary-light: #0099FF;   /* bright tab blue */
    --color-primary: #0066CC;         /* main nav blue */
    --color-secondary-yellow: #FFF7A5;/* content cards */
    --color-secondary-pink: #F080A0;  /* accent */
    --color-accent-red: #FF0000;      /* alerts, emphasis */

    --color-neutral-white: #FFFFFF;
    --color-neutral-page-bg: #E5E5E5; /* outer background */
    --color-neutral-light: #F2F2F2;   /* sidebar */
    --color-neutral-border: #CCCCCC;  /* borders */
    --color-neutral-text: #333333;

    --semantic-success: #4CAF50;
    --semantic-error: #FF0000;
    --semantic-warning: #FFF7A5;
    --semantic-info: #0099FF;

    /* Typography */
    --font-heading: "DM Sans", Helvetica, sans-serif;
    --font-body: "Libre Baskerville", Georgia, serif;
    --font-code: "Source Code Pro", monospace;

    --fs-h1: 24px;
    --fs-h2: 18px;
    --fs-h3: 16px;
    --fs-body: 13px;
    --fs-small: 11px;

    --fw-light: 300;
    --fw-regular: 400;
    --fw-medium: 500;
    --fw-semibold: 600;
    --fw-bold: 700;

    --lh-tight: 1.2;
    --lh-normal: 1.4;
    --lh-relaxed: 1.6;

    /* Spacing scale */
    --space-1: 4px;
    --space-2: 8px;
    --space-3: 12px;
    --space-4: 16px;
    --space-5: 24px;
    --space-6: 32px;
    --space-7: 48px;

    /* Layout */
    --page-width: 960px;
}

/* ===== Global reset-like rules (lightweight) ===== */

* {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
}

body {
    background-color: var(--color-neutral-page-bg);
    color: var(--color-neutral-text);
    font-family: var(--font-body);
    font-size: var(--fs-body);
    line-height: var(--lh-relaxed);
}

a {
    color: var(--color-primary);
    text-decoration: underline;
}

a:hover,
a:focus {
    text-decoration: none;
}

img {
    max-width: 100%;
    height: auto;
    border: 0;
}

.page-wrapper {
    width: var(--page-width);
    margin: 0 auto;
    background-color: var(--color-neutral-white);
    border-left: 1px solid var(--color-neutral-border);
    border-right: 1px solid var(--color-neutral-border);
}

/* ===== Header ===== */

.site-header {
    background-color: var(--color-neutral-white);
    border-bottom: 1px solid var(--color-neutral-border);
}

.header-top {
    display: flex;
    align-items: stretch;
}

/* Left branding area: face/photo + clinic name */

.header-branding {
    flex: 1 1 65%;
    border-right: 1px solid var(--color-neutral-border);
}

.branding-inner {
    display: flex;
    align-items: stretch;
}

.brand-photo-placeholder {
    width: 260px;
    min-height: 120px;
    background: linear-gradient(135deg, #FFE9EE 0%, #FFFFFF 40%, #CFE6FF 100%);
    border-right: 1px solid var(--color-neutral-border);
}

.brand-text {
    padding: var(--space-3) var(--space-4);
    display: flex;
    flex-direction: column;
    justify-content: center;
}

.clinic-name {
    font-family: var(--font-heading);
    font-size: var(--fs-h1);
    font-weight: var(--fw-semibold);
    color: var(--color-primary);
    margin-bottom: var(--space-2);
}

.clinic-tagline {
    font-size: var(--fs-small);
    line-height: var(--lh-normal);
    color: #666666;
}

/* Right header: blue gradient with vertical links */

.header-utility {
    flex: 0 0 35%;
}

.utility-background {
    height: 120px;
    padding: var(--space-3) var(--space-4);
    background: linear-gradient(to bottom, #E5F4FF 0%, #A7D7FF 40%, #5BB8FF 100%);
    position: relative;
}

.site-title {
    margin: 0 0 var(--space-2) 0;
    font-family: var(--font-heading);
    font-size: var(--fs-h2);
    font-weight: var(--fw-bold);
    color: var(--color-neutral-white);
    letter-spacing: 0.5px;
}

.utility-nav {
    position: absolute;
    right: var(--space-4);
    bottom: var(--space-3);
}

.utility-nav ul {
    list-style: none;
    margin: 0;
    padding: 0;
}

.utility-nav li {
    margin: 0 0 2px 0;
    text-align: right;
}

.utility-nav a {
    font-family: var(--font-heading);
    font-size: var(--fs-small);
    font-weight: var(--fw-medium);
    color: var(--color-neutral-white);
    text-decoration: none;
    text-transform: uppercase;
}

.utility-nav a:hover,
.utility-nav a:focus {
    text-decoration: underline;
}

/* ===== Main navigation bar ===== */

.main-nav {
    background-color: var(--color-primary);
    border-top: 1px solid #0055AA;
    border-bottom: 3px solid #004C99;
}

.main-nav-list {
    list-style: none;
    margin: 0;
    padding: 0;
    font-family: var(--font-heading);
    font-size: var(--fs-body);
    font-weight: var(--fw-semibold);
    white-space: nowrap;
}

.main-nav-list li {
    display: inline-block;
}

.main-nav-list a {
    display: inline-block;
    padding: 6px 14px 6px 18px;
    color: var(--color-neutral-white);
    text-decoration: none;
    border-right: 1px solid rgba(255, 255, 255, 0.6);
}

.main-nav-list a::before {
    content: ">> ";
    font-size: 11px;
}

.main-nav-list a:hover,
.main-nav-list a:focus {
    background-color: var(--color-primary-light);
    text-decoration: underline;
}

/* ===== Layout: content + sidebar ===== */

.layout {
    display: flex;
    align-items: stretch;
    border-top: 1px solid var(--color-neutral-border);
}

.content-area {
    flex: 1 1 auto;
    padding: var(--space-5) var(--space-5) var(--space-6);
    border-right: 1px solid var(--color-neutral-light);
    min-height: 300px;
}

.sidebar {
    flex: 0 0 240px;
    background-color: var(--color-neutral-light);
    padding: var(--space-4);
    font-size: var(--fs-small);
    line-height: var(--lh-normal);
}

/* ===== Footer ===== */

.site-footer {
    border-top: 1px solid var(--color-neutral-border);
}

.footer-nav-wrapper {
    background: linear-gradient(to bottom, var(--color-primary-light), var(--color-primary));
    border-top: 1px solid #0055AA;
    border-bottom: 1px solid #004C99;
}

.footer-nav {
    padding: 6px var(--space-4);
}

.footer-nav ul {
    list-style: none;
    margin: 0;
    padding: 0;
    text-align: center;
    font-family: var(--font-heading);
    font-size: var(--fs-small);
}

.footer-nav li {
    display: inline;
    margin: 0 6px;
}

.footer-nav a {
    color: var(--color-neutral-white);
    text-decoration: none;
}

.footer-nav a::before {
    content: ">> ";
}

.footer-nav a:hover,
.footer-nav a:focus {
    text-decoration: underline;
}

.footer-meta {
    padding: 10px var(--space-4) 14px;
    text-align: center;
    font-size: var(--fs-small);
    color: #666666;
    background-color: var(--color-neutral-white);
}

.footer-meta .footer-year {
    font-weight: var(--fw-semibold);
}

/* ===== Headings & text utilities ===== */

h1, h2, h3, h4 {
    font-family: var(--font-heading);
    margin-top: 0;
    margin-bottom: var(--space-3);
    line-height: var(--lh-tight);
}

h1 { font-size: var(--fs-h1); }

h2 { font-size: var(--fs-h2); }

h3 { font-size: var(--fs-h3); }

p {
    margin-top: 0;
    margin-bottom: var(--space-3);
}

.small-text {
    font-size: var(--fs-small);
}

/* ===== Media queries (minor responsiveness) ===== */

@media (max-width: 980px) {
    .page-wrapper {
        width: 100%;
        border-left: none;
        border-right: none;
    }
}

@media (max-width: 800px) {
    .header-top {
        flex-direction: column;
    }

    .utility-background {
        height: auto;
    }

    .utility-nav {
        position: static;
        margin-top: var(--space-2);
    }

    .layout {
        flex-direction: column;
    }

    .sidebar {
        border-top: 1px solid var(--color-neutral-border);
        flex-basis: auto;
    }
}
